var e=[{id:`L2_1`,type:`subtitle`,speaker:null,text:{KOREA:`6개월 뒤`,JPN:`6か月後`,ENG:`6 months later`,TWN:`6個月後`,THA:`6 เดือนต่อมา`,VTN:`6 tháng sau`,SCN:`6个月后`,DEU:`6 Monate später`,FRA:`6 mois plus tard`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`subtitle`,speaker:null,text:{KOREA:`인류 통합 방위군 제7 방위선 탈환 작전`,JPN:`人類統合防衛軍による第7防衛線奪還作戦`,ENG:`Operation Takeover United Humankind Defense Force's 7th Defense Line`,TWN:`奪回人類共同保衛軍第七防線作戰`,THA:`ปฏิบัติการยึดแนวป้องกันที่ 7 กองกำลังป้องกันมนุษยชาติ`,VTN:`Chiến dịch tiếp quản Phòng Tuyến thứ 7 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất`,SCN:`人类综合防卫军第7防线夺回战`,DEU:`Operation „Übernahme der 7. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit“`,FRA:`Opération Reconquête, 7e ligne de défense des Forces de défense unies de l'humanité`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_A`,text:{KOREA:`이 고지만 되찾으면, 네피림 사태 때 잃어버린 제7 방위선을 회복할 수 있다!`,JPN:`このポイントさえ取り返せば、ネフィリム事件の際に失われた第7防衛線を回復させられる！`,ENG:`If we take this high ground, we will be able to reclaim the 7th Defense Line, which we lost during the Nephil incident!`,TWN:`只要奪回這個高地，我們就有希望恢復在諾菲力事件中丟失的第七防線了！`},stage:{bg:`PROLOGUE_01`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_A`,text:{KOREA:`목숨이 끝나는 한이 있더라도! 빌어먹을 침식체들에게 인간의 저력을 보여주는 거다!`,JPN:`命を落とそうとも！　クソッたれの侵食体どもに人間の底力を見せてやるんだ！`,ENG:`Even if it means sacrificing our lives! We must show those C.O. bastards what humans are capable of!`,TWN:`一定要讓這些該死的侵蝕體們嚐嚐人類的厲害！哪怕我們全部犧牲！`},stage:{bg:`PROLOGUE_01`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`제기랄, 총알이 다 떨어졌어! 누구 총알 가진 거 더 없어!?`,JPN:`くそっ、弾切れだ！　誰かまだ弾が残っている者はいないか！？`,ENG:`Dammit! I'm outta ammo! Does anyone have a mag?!`,TWN:`可惡，沒子彈了！誰還有子彈？！`},stage:{bg:`PROLOGUE_01`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:null,text:{KOREA:`이봐, 정신 차려!! 이제 고지가 코 앞인데 여기서 죽으면 어쩌자는 거야!!`,JPN:`おい、しっかりしろ！！　目標地点まであと少しだというのに、ここで死んでどうする！！`,ENG:`Hey, pull yourself together!! We're almost there, you can't die here!!`,TWN:`喂，醒醒！！差一步就能奪回高地了，可不能在這裡倒下！！`},stage:{bg:`PROLOGUE_01`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:`이거나 쳐 먹어라, 이 괴물 자식들아!!`,JPN:`これでも食らえ、この化け物ども！！`,ENG:`Eat this, you damn monsters!!`,TWN:`你們這些怪物，吃我一槍！！`},stage:{bg:`PROLOGUE_01`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_B`,text:{KOREA:`크윽, 이봐! 항공 지원은 아직이야?`,JPN:`くっ、おい！　航空支援はまだなのか？`,ENG:`Kgh, hey! What's the ETA for the air support?!`,TWN:`咳呃，喂！空中支援還沒到嗎？`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_B`,text:{KOREA:`예상보다 침식체의 숫자가 너무 많아! 지상 병력으로만 제압하기는 어렵겠어!`,JPN:`予想以上に侵食体の数が多い！　地上兵力だけでは制圧は無理だ！`,ENG:`There are too many C.O.s here! We can't kill them all by ourselves!`,TWN:`侵蝕體的數量超出預想的太多了！只靠地面兵力很難壓制他們！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`제기랄, 이럴 때 카운터가 있었더라면!`,JPN:`くそ、こんな時にカウンターがいればな！`,ENG:`Damn it, if only there was a Counter!`,TWN:`可惡，這種時候有制裁者就好了！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:{char_id:`GUARD_EXILER_NPC_B`,face:`UNIT_IDLE`},C:null,R:{char_id:`GUARD_EXILER_NPC_C`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_A`,text:{KOREA:`시끄러워, 불평할 시간이 있으면 총알 한 발이라도 더 쏴 갈기라고!`,JPN:`うるせえ、文句を言っている暇があるなら、弾を一発でも多くぶち込むことに集中しろ！`,ENG:`Shut it! Shoot 'em if you've got time to whine!`,TWN:`吵死了，有這抱怨的時間，還不如多射一發子彈!`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_A`,face:`UNIT_IDLE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_A`,text:{KOREA:`뭐지? 방금 장갑차가 꿈틀거렸던 것 같은데……?`,JPN:`なんだ？　今装甲車が浮き上がったような……？`,ENG:`Huh? Is it me, or did that armored vehicle just twitch...?`,TWN:`嗯？剛剛裝甲車好像晃了一下……？`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_A`,face:`UNIT_IDLE`},R:null}}},{id:`L39_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_A`,text:{KOREA:`이런 제기랄!!`,JPN:`くそ、まじかっ！！`,ENG:`Goddammit!`,TWN:`見鬼！！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:null,C:{char_id:`GUARD_EXILER_NPC_A`,face:`UNIT_IDLE`},R:null}}}];export{e as default};